import React,{ lazy } from 'react';

import { Routes,Route,BrowserRouter} from "react-router-dom";



import Navbars from './component/Navbars';
// import Footer from './component/footer';


import Signup from './component/Signup'
import Signin from './component/Signin'
import Loading from './component/Loading.js';
import NotFound from './component/NotFound.js'
// import './component/css/Cards.css'
import './App.css';



// const Home = lazy(()=> import('./component/Home.js'))
const Home2 = lazy(()=> import('./component/home2.js'))
const Click = lazy(()=> import('./component/click.js'))
const IT = lazy(()=> import('./component/it/Employee.js'))
const ITP = lazy(()=> import('./component/it/testP.js'))
const Client = lazy(()=> import('./component/client.js'))
const Adduser = lazy(()=> import('./component/it/adduser.js'))
const Employeetable = lazy(()=> import('./component/it/Employeetable.js'))
const Ittable = lazy(()=> import('./component/it/ittable.js'))
const Alldata = lazy(()=> import('./component/it/allDate.js'))
// const  Chatbot = lazy(()=> import('./component/chatbot/chat.js'))
// const  Pages = lazy(()=> import('./component/page.js'))
// const  Department = lazy(()=> import('./component/Department.js'))




const App = ()=>{
 

  return (
    
    <BrowserRouter>
    
    <div className="App">
    
      
   
        <Routes>
      
        {/* <Route path="/" element={<Signup/>}/> */}
        <Route path="/SignupUser" element={<Signup/>}/>
        {/* <Route path="/" element={<Signin/>}/> */}
        <Route path="/signin" element={<Signin/>}/>

        {/* private */}
        <Route path="/ITP" element={<ITP/>}/>
        <Route path="/Ittable" element={<Ittable/>}/>
        {/* private */}
       
        <Route path="/adduser" element={
            <React.Suspense fallback={<Loading/>}>

            <div>
          <Navbars />
          <Adduser/>
          </div>
          </React.Suspense>
          }
          />
        <Route path="/Alldata" element={
            <React.Suspense fallback={<Loading/>}>

            <div>
          <Navbars />
          <Alldata/>
          </div>
          </React.Suspense>
          }
          />
        <Route path="/Employeetable" element={
           <React.Suspense fallback={<Loading/>}>
           <div>
          <Navbars />
          <Employeetable/>
          </div>
          </React.Suspense>
        }
          />

         <Route path="*" element={
          <div>
          <Navbars />
         <NotFound/>
         </div>
         }/>
          
         {/* chatbot */}
     

          {/* Home */}
      
          <Route path="/" element={
            <React.Suspense fallback={<Loading/>}>
            <div>
          <Navbars />
                    
           < Home2 />
          
          
          {/* <Footer/> */}
          </div>
          </React.Suspense>
        }/>

          <Route path="/Reports" element={
            <React.Suspense fallback={<Loading/>}>
            <div>
          <Navbars />
                    
           < Click />
          
          
          {/* <Footer/> */}
          </div>
          </React.Suspense>
        }/>

     

          <Route path="/IT" element={
            <React.Suspense fallback={<Loading/>}>
            <div>
          <Navbars />
                    
           < IT />
          
          
          {/* <Footer/> */}
          </div>
          </React.Suspense>
        }/>
          <Route path="/Client" element={
            <React.Suspense fallback={<Loading/>}>
            <div>
          <Navbars />
                    
           < Client />
          
          
          {/* <Footer/> */}
          </div>
          </React.Suspense>
        }/>
        
       

        </Routes>
        
    </div>
    
    {/* <Footer/> */}
    </BrowserRouter>
    
  );
}

export default App;
